    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0x8CE7CDA095E3FF87ULL + 0xA54562084BCE636AULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xDAB938712370B819ULL + 0xFA57F309618E449BULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseB(pNonce * 0xB060D457CEEB11D9ULL + 0xC95A513E05649A34ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseA(pNonce * 0xDC94670755B1487FULL + 0xF8FA826CF54DD682ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseA(pNonce * 0xEF844F630DDE23A5ULL + 0x85AE7D31BA107C26ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseA(pNonce * 0xFB6B180D373708A7ULL + 0xB5F0227D7332125DULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseB(pNonce * 0xD55A2DFF16460967ULL + 0x88A6FA675CE38440ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0x903E234B8644FFDBULL + 0xCDBEC2C66E9EE09EULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0x8E3157E3858AE271ULL + 0x869F5AB81FCFA32CULL);
