            aOrbiterC = (aOrbiterC + aOrbiterB) + 7412169842977028240U;
            aOrbiterG = (aOrbiterG ^ aOrbiterC) ^ 7305631479883076955U;
            aOrbiterG = RotL64((aOrbiterG * 9395153101573413011U), 41U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterE) + 16119900558894176589U;
            aOrbiterB = (aOrbiterB ^ aOrbiterH) ^ 7798500863752233307U;
            aOrbiterB = RotL64((aOrbiterB * 16923414830403928691U), 13U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterA) + 12207754967612949673U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterK) ^ 13327540202622782258U;
            aOrbiterE = RotL64((aOrbiterE * 5357168329920459517U), 51U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterD) + 4851594037382105982U) + aOrbiterUpdateSaltD[((aIndex + 29U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterB) ^ 6255626732535006007U;
            aOrbiterK = RotL64((aOrbiterK * 5359373141994302031U), 35U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterG) + 15116429139071755571U;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 6086759762206135077U;
            aOrbiterF = RotL64((aOrbiterF * 2601900182270094645U), 43U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterJ) + 13757973668625545014U;
            aOrbiterA = ((aOrbiterA ^ aOrbiterD) ^ 4326064364859555195U) ^ aNonceWordL;
