            //
            aOrbiterI = (aOrbiterI + aOrbiterC) + 1052523299953789588U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterI) ^ 5856358092644723252U;
            aOrbiterJ = RotL64((aOrbiterJ * 5663299534249413133U), 53U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterH) + 3940514074448672080U;
