            aOrbiterD = RotL64((aOrbiterD * 5299467361949522245U), 27U);
            //
            aIngress = aOrbiterI ^ RotL64(aOrbiterA, 13U);
            aIngress = aIngress + (RotL64(aOrbiterG, 18U) ^ aOrbiterH);
            aIngress = aIngress + (RotL64(aOrbiterD, 29U) ^ aOrbiterJ);
            aIngress = aIngress + (aOrbiterE ^ RotL64(aOrbiterC, 23U));
            aIngress = aIngress + (aOrbiterK ^ RotL64(aOrbiterB, 3U));
            aIngress = aIngress + RotL64(aOrbiterF, 41U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererD = aWandererD + (((RotL64(aCross, 29U) + RotL64(aOrbiterI, 19U)) + aOrbiterJ) + aWandererUpdateSaltD[((aIndex + 7U)) & S_SALT1]);
            aWandererC = aWandererC ^ (((RotL64(aIngress, 19U) + RotL64(aOrbiterG, 11U)) + aOrbiterD) + aNonceWordD);
            aWandererJ = aWandererJ + ((RotL64(aScatter, 11U) + RotL64(aOrbiterD, 6U)) + aOrbiterF);
