            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 8218219763121976889U;
            aOrbiterF = (aOrbiterF ^ aOrbiterE) ^ 9121854584492109038U;
            aOrbiterF = RotL64((aOrbiterF * 10360491670292802705U), 53U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterD) + 648933430858779807U;
            aOrbiterK = ((aOrbiterK ^ aOrbiterF) ^ 9384717150161332299U) ^ aNonceWordB;
            aOrbiterK = RotL64((aOrbiterK * 15093538775620093609U), 51U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterG) + 2677471703553987834U;
            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 2596401778652353658U;
            aOrbiterA = RotL64((aOrbiterA * 12793172571837843795U), 13U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterI) + 3143944667586752404U) + aOrbiterUpdateSaltB[((aIndex + 14U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 2257633279096561207U;
            aOrbiterC = RotL64((aOrbiterC * 8580672390423781273U), 27U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterC) + 7571442185603419062U) + aOrbiterUpdateSaltE[((aIndex + 27U)) & S_SALT1];
            aOrbiterH = ((aOrbiterH ^ aOrbiterK) ^ 4392580663689927878U) ^ aOrbiterUpdateSaltF[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterH = RotL64((aOrbiterH * 16271406592847992177U), 29U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterK) + 6495081469198191482U;
